import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { 
  DocumentTextIcon, 
  ChartBarIcon, 
  MagnifyingGlassIcon,
  LightBulbIcon,
  ClockIcon,
  ArrowRightIcon
} from '@heroicons/react/24/outline';

const Home = () => {
  const { user } = useAuth();

  if (user) {
    window.location.href = '/dashboard';
    return null;
  }

  const features = [
    {
      icon: DocumentTextIcon,
      title: "Resume Upload",
      description: "Upload your resume in PDF or DOCX format. The system extracts text for analysis."
    },
    {
      icon: MagnifyingGlassIcon,
      title: "Job Description",
      description: "Paste the job description you want to compare against your resume."
    },
    {
      icon: ChartBarIcon,
      title: "ATS Score",
      description: "Get a score showing how well your resume matches the job requirements."
    },
    {
      icon: LightBulbIcon,
      title: "Skill Analysis",
      description: "See which skills match and which skills are missing from the job description."
    },
    {
      icon: ClockIcon,
      title: "Analysis History",
      description: "Save your analyses to track changes over time."
    }
  ];

  return (
    <div className="bg-white">
      {/* Hero Section */}
      <div className="bg-indigo-700">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16">
          <div className="text-center">
            <h1 className="text-4xl font-bold text-white mb-4">
              Resume Analyzer
            </h1>
            <p className="text-lg text-indigo-100 mb-8 max-w-2xl mx-auto">
              Upload your resume, paste a job description, and get analysis on how well they match.
            </p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              <Link to="/register">
                <button className="px-6 py-3 bg-white text-indigo-700 rounded-lg font-medium hover:bg-gray-100">
                  Get Started
                </button>
              </Link>
              <Link to="/login">
                <button className="px-6 py-3 border-2 border-white text-white rounded-lg font-medium hover:bg-white/10">
                  Sign In
                </button>
              </Link>
            </div>
          </div>
        </div>
      </div>

      {/* Features Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="text-center mb-8">
          <h2 className="text-2xl font-bold text-gray-900">Features</h2>
          <p className="text-gray-600 mt-2">What this application does</p>
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {features.map((feature, index) => (
            <div key={index} className="border border-gray-200 rounded-lg p-5 hover:shadow-md transition">
              <div className="inline-flex p-2 bg-gray-100 rounded-lg mb-3">
                <feature.icon className="h-5 w-5 text-gray-700" />
              </div>
              <h3 className="font-semibold text-gray-900 mb-1">{feature.title}</h3>
              <p className="text-sm text-gray-600">{feature.description}</p>
            </div>
          ))}
        </div>
      </div>

      {/* How It Works */}
      <div className="bg-gray-50 py-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-8">
            <h2 className="text-2xl font-bold text-gray-900">How to Use</h2>
            <p className="text-gray-600 mt-2">Simple steps to analyze your resume</p>
          </div>
          
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            {[
              { step: "1", title: "Create Account", desc: "Sign up with email" },
              { step: "2", title: "Upload Resume", desc: "PDF or DOCX file" },
              { step: "3", title: "Paste Job Description", desc: "Copy from job posting" },
              { step: "4", title: "View Results", desc: "See analysis and suggestions" }
            ].map((step, index) => (
              <div key={index} className="bg-white rounded-lg p-5 text-center border border-gray-200">
                <div className="w-10 h-10 bg-gray-200 text-gray-700 rounded-full flex items-center justify-center text-lg font-semibold mx-auto mb-3">
                  {step.step}
                </div>
                <h3 className="font-semibold text-gray-900 mb-1">{step.title}</h3>
                <p className="text-sm text-gray-500">{step.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* CTA */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 text-center">
        <h2 className="text-2xl font-bold text-gray-900 mb-4">
          Start analyzing your resume
        </h2>
        <Link to="/register">
          <button className="px-6 py-3 bg-indigo-600 text-white rounded-lg font-medium hover:bg-indigo-700">
            Create Free Account
          </button>
        </Link>
        <p className="text-sm text-gray-500 mt-3">No credit card required</p>
      </div>
    </div>
  );
};

export default Home;
